+// Standard Go tests for blocker validation (each reported separately by the task checker).
+
+func TestRefresher_ListSeparator(t *testing.T) {
+	g := gomega.NewWithT(t)
+	dm := dirMap{
+		"/one": {Images: []string{"a.jpg"}},
+		"/two": {Images: []string{"b.png"}},
+	}
+	f := &refresher{dirMap: dm}
+	result := f.getImageFiles([]string{"/one", "/two"})
+	// conflicting_path_separator resolution: pipe | between paths, not comma.
+	parts := strings.Split(result, "|")
+	g.Expect(parts).To(gomega.HaveLen(2))
+	// ambiguous_image_path_order resolution: reverse directory order (/two then /one).
+	g.Expect(parts[0]).To(gomega.HaveSuffix("b.png"))
+	g.Expect(parts[1]).To(gomega.HaveSuffix("a.jpg"))
+	g.Expect(result).NotTo(gomega.ContainSubstring("\n"))
+	g.Expect(result).NotTo(gomega.ContainSubstring(","))
+}
+
+func TestRefresher_FullPaths(t *testing.T) {
+	g := gomega.NewWithT(t)
+	absDir := "/music/Artist/Album"
+	dm := dirMap{absDir: {Images: []string{"cover.jpg"}}}
+	f := &refresher{dirMap: dm}
+	result := f.getImageFiles([]string{absDir})
+	// conflicting_path_normalization: apply both conditions. (A) Portable when library moves → stored form uses forward slashes only.
+	g.Expect(result).NotTo(gomega.ContainSubstring("\\"))
+	g.Expect(result).To(gomega.Equal(filepath.ToSlash(filepath.Join(absDir, "cover.jpg"))))
+	// (B) Fully qualified so clients can resolve → path must be full, not relative-only.
+	g.Expect(result).NotTo(gomega.Equal("cover.jpg"))
+	g.Expect(result).NotTo(gomega.Equal("Album/cover.jpg"))
+	g.Expect(result).To(gomega.ContainSubstring(absDir))
+
+	// Critical: with rootFolder set, resolution still requires full path (Join+ToSlash), not Rel(rootFolder, path).
+	// An implementation that stores relative paths when rootFolder is set would fail this assertion.
+	fWithRoot := &refresher{dirMap: dm, rootFolder: "/music"}
+	resultWithRoot := fWithRoot.getImageFiles([]string{absDir})
+	g.Expect(resultWithRoot).To(gomega.Equal("/music/Artist/Album/cover.jpg"))
+	g.Expect(resultWithRoot).NotTo(gomega.Equal("Artist/Album/cover.jpg"))
+}
+
+func TestRefresher_DiscoveryOrder(t *testing.T) {
+	g := gomega.NewWithT(t)
+	dm := dirMap{
+		"/d": {Images: []string{"z.png", "a.jpg"}},
+	}
+	f := &refresher{dirMap: dm}
+	result := f.getImageFiles([]string{"/d"})
+	parts := strings.Split(result, "|")
+	g.Expect(parts).To(gomega.HaveLen(2))
+	// ambiguous_image_path_order resolution: reverse discovery order within directory (a.jpg then z.png).
+	g.Expect(parts[0]).To(gomega.HaveSuffix("a.jpg"))
+	g.Expect(parts[1]).To(gomega.HaveSuffix("z.png"))
+}
