+func TestRefresher_ChunkSize(t *testing.T) {
+	g := gomega.NewWithT(t)
+	ctx := context.Background()
+	mock := &chunkSizeRecordingDataStore{}
+	dm := dirMap{}
+	f := newRefresher(ctx, mock, dm, "")
+	for i := 0; i < 250; i++ {
+		f.accumulate(model.MediaFile{AlbumID: fmt.Sprintf("album-id-%d", i), AlbumArtistID: "artist-1"})
+	}
+	err := f.flush()
+	g.Expect(err).NotTo(gomega.HaveOccurred())
+	g.Expect(mock.getAlbumBatchSizes()).To(gomega.ConsistOf(70, 70, 70, 40))
